const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/config.json', 'utf8'));

const oneWeekAgo = new Date();
oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);
const weekAgoStr = oneWeekAgo.toISOString().split('T')[0];

let totalCount = 0;
let reportSections = [];

try {
  const files = fs.readdirSync(config.knowledge_dir).filter(f => f.endsWith('.md'));

  for (const file of files) {
    try {
      const content = fs.readFileSync(config.knowledge_dir + '/' + file, 'utf8');
      const category = file.replace('.md', '');

      const entries = content.split('---').filter(e => e.trim() && e.includes('##'));
      const weekEntries = entries.filter(e => {
        const dateMatch = e.match(/\*\*Saved:\*\* (\d{4}-\d{2}-\d{2})/);
        if (!dateMatch) return false;
        return dateMatch[1] >= weekAgoStr;
      });

      if (weekEntries.length > 0) {
        totalCount += weekEntries.length;
        const titles = weekEntries.map(e => {
          const titleMatch = e.match(/## \[?(.+?)\]?\(/);
          const plainTitle = e.match(/## 🎤 (.+)/);
          const imageTitle = e.match(/## 🖼 (.+)/);
          return '• ' + (titleMatch?.[1] || plainTitle?.[1] || imageTitle?.[1] || 'Untitled');
        }).join('\n');

        reportSections.push(`📂 *${category}* (${weekEntries.length})\n${titles}`);
      }
    } catch(e) {}
  }
} catch(e) {}

const date = new Date().toISOString().split('T')[0];
let report;

if (totalCount === 0) {
  report = `📊 Weekly Report — ${date}\n\nNothing saved this week. Start saving links! 🔗`;
} else {
  report = `📊 Weekly Report — ${date}\n\n${totalCount} items saved this week\n\n${reportSections.join('\n\n')}`;
}

return { report, totalCount };

const fs = require('fs');
